                    style={{ borderColor: "#e8e8e5" }}
                  >
                    <div className="flex items-center gap-2.5">
                      <VersionChip version={sr.version} />
                      <StatusDot status={sr.status} />
                      <span className="text-[13px]" style={{ color: "#6b7280" }}>
                        {sr.status}
